/**
 * @suppress
 */
public object FfiConverterTypeVPNManager: FfiConverter<VpnManager, Pointer> {

    override fun lower(value: VpnManager): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): VpnManager {
        return VpnManager(value)
    }

    override fun read(buf: ByteBuffer): VpnManager {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: VpnManager) = 8UL

    override fun write(value: VpnManager, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}



