sealed class ShadowMeshException(message: String): kotlin.Exception(message) {
        
        class KeyGenerationFailed(message: String) : ShadowMeshException(message)
        
        class PowTimeout(message: String) : ShadowMeshException(message)
        
        class ConnectionFailed(message: String) : ShadowMeshException(message)
        
        class NodeNotFound(message: String) : ShadowMeshException(message)
        
        class IoException(message: String) : ShadowMeshException(message)
        
        class JsonException(message: String) : ShadowMeshException(message)
        
        class Other(message: String) : ShadowMeshException(message)
        

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<ShadowMeshException> {
        override fun lift(error_buf: RustBuffer.ByValue): ShadowMeshException = FfiConverterTypeShadowMeshError.lift(error_buf)
    }
}

/**
 * @suppress
 */
public object FfiConverterTypeShadowMeshError : FfiConverterRustBuffer<ShadowMeshException> {
    override fun read(buf: ByteBuffer): ShadowMeshException {
        
            return when(buf.getInt()) {
            1 -> ShadowMeshException.KeyGenerationFailed(FfiConverterString.read(buf))
            2 -> ShadowMeshException.PowTimeout(FfiConverterString.read(buf))
            3 -> ShadowMeshException.ConnectionFailed(FfiConverterString.read(buf))
            4 -> ShadowMeshException.NodeNotFound(FfiConverterString.read(buf))
            5 -> ShadowMeshException.IoException(FfiConverterString.read(buf))
            6 -> ShadowMeshException.JsonException(FfiConverterString.read(buf))
            7 -> ShadowMeshException.Other(FfiConverterString.read(buf))
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
        
    }

    override fun allocationSize(value: ShadowMeshException): ULong {
        return 4UL
    }

    override fun write(value: ShadowMeshException, buf: ByteBuffer) {
        when(value) {
            is ShadowMeshException.KeyGenerationFailed -> {
                buf.putInt(1)
                Unit
            }
            is ShadowMeshException.PowTimeout -> {
                buf.putInt(2)
                Unit
            }
            is ShadowMeshException.ConnectionFailed -> {
                buf.putInt(3)
                Unit
            }
            is ShadowMeshException.NodeNotFound -> {
                buf.putInt(4)
                Unit
            }
            is ShadowMeshException.IoException -> {
                buf.putInt(5)
                Unit
            }
            is ShadowMeshException.JsonException -> {
                buf.putInt(6)
                Unit
            }
            is ShadowMeshException.Other -> {
                buf.putInt(7)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




